class Solution(object):
    def numberOfGoodSubarraySplits(self, nums):
        MOD = 10**9 + 7
        ones = [i for i, v in enumerate(nums) if v == 1]
        if not ones:
            return 0
        result = 1
        for i in range(1, len(ones)):
            result = result * (ones[i] - ones[i - 1]) % MOD
        return result
